const e=JSON.parse(`{"key":"v-ea49eec8","path":"/posts/rcc%E7%BC%96%E8%AF%91%E5%99%A8/Chapter1%E8%AF%8D%E6%B3%95%E5%88%86%E6%9E%90%E5%99%A8%E4%B9%8BChumsky.html","title":"Chapter1 词法分析器之Chumsky","lang":"zh-CN","frontmatter":{"title":"Chapter1 词法分析器之Chumsky","icon":"page","order":1,"author":"ChiChen","category":["笔记","编译器"],"tag":["编译器","词法分析"],"sticky":false,"star":false,"footer":null,"isOriginal":true,"copyright":"转载请注明出处","description":"库的选择 一开始我其实是选择的nom这个库来完成词法分析的，但是写了一段时间之后还是选择了chumsky，有几点因素在里面： 左递归问题：其实nom写起来要比chumsky优雅很多，因为前者的主题是一系列函数指针，类型很清晰，但是后者是泛型对象，一旦报错就是嵌套几十层的泛型可读性几乎为零，而且前者是PEC(Parser Expression Combinator)，可以把每个函数的职责划分得很清楚，而后者是 PEG(Parser Expression Generator)，相对来说没有这么优雅。但是这一切都被左递归打破了。大多数学生都知道，消除左递归的方法就是重写文法，然而重写文法会导致每个产生式之间的大量耦合，使得原来职责清晰的函数变得很答辩。而chumsky使用了packrat算法(求证中)，来实现对左递归的消除，大大提高了产生式的可读性，虽然仍然需要解决一部分的优先级问题，但是比起nom来说已经是好太多了 错误恢复和抛出：在编译器中，错误处理其实是很重要的一部分，这直接关系到用户的编程体验，chumsky恰恰是考虑到了这点，它有一个孪生的ariadne库，可以生成一些可视化程度较高的错误信息，而且在分析的过程中提供了错误恢复的操作，这些都是nom缺乏的","head":[["meta",{"property":"og:url","content":"https://chiichen.github.io/posts/rcc%E7%BC%96%E8%AF%91%E5%99%A8/Chapter1%E8%AF%8D%E6%B3%95%E5%88%86%E6%9E%90%E5%99%A8%E4%B9%8BChumsky.html"}],["meta",{"property":"og:site_name","content":"ChiChen's Blog"}],["meta",{"property":"og:title","content":"Chapter1 词法分析器之Chumsky"}],["meta",{"property":"og:description","content":"库的选择 一开始我其实是选择的nom这个库来完成词法分析的，但是写了一段时间之后还是选择了chumsky，有几点因素在里面： 左递归问题：其实nom写起来要比chumsky优雅很多，因为前者的主题是一系列函数指针，类型很清晰，但是后者是泛型对象，一旦报错就是嵌套几十层的泛型可读性几乎为零，而且前者是PEC(Parser Expression Combinator)，可以把每个函数的职责划分得很清楚，而后者是 PEG(Parser Expression Generator)，相对来说没有这么优雅。但是这一切都被左递归打破了。大多数学生都知道，消除左递归的方法就是重写文法，然而重写文法会导致每个产生式之间的大量耦合，使得原来职责清晰的函数变得很答辩。而chumsky使用了packrat算法(求证中)，来实现对左递归的消除，大大提高了产生式的可读性，虽然仍然需要解决一部分的优先级问题，但是比起nom来说已经是好太多了 错误恢复和抛出：在编译器中，错误处理其实是很重要的一部分，这直接关系到用户的编程体验，chumsky恰恰是考虑到了这点，它有一个孪生的ariadne库，可以生成一些可视化程度较高的错误信息，而且在分析的过程中提供了错误恢复的操作，这些都是nom缺乏的"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-11-23T13:14:12.000Z"}],["meta",{"property":"article:author","content":"ChiChen"}],["meta",{"property":"article:tag","content":"编译器"}],["meta",{"property":"article:tag","content":"词法分析"}],["meta",{"property":"article:modified_time","content":"2023-11-23T13:14:12.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Chapter1 词法分析器之Chumsky\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2023-11-23T13:14:12.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"ChiChen\\"}]}"]]},"headers":[{"level":2,"title":"库的选择","slug":"库的选择","link":"#库的选择","children":[]}],"git":{"createdTime":1700745252000,"updatedTime":1700745252000,"contributors":[{"name":"chiichen","email":"chiichen@qq.com","commits":1}]},"readingTime":{"minutes":1.88,"words":565},"filePathRelative":"posts/rcc编译器/Chapter1词法分析器之Chumsky.md","localizedDate":"2023年11月23日","excerpt":"<h2> 库的选择</h2>\\n<p>一开始我其实是选择的<a href=\\"https://docs.rs/nom/7.1.3/nom/index.html\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">nom</a>这个库来完成词法分析的，但是写了一段时间之后还是选择了<a href=\\"https://docs.rs/chumsky/1.0.0-alpha.6/chumsky/index.html\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">chumsky</a>，有几点因素在里面：</p>\\n<ol>\\n<li>左递归问题：其实<code>nom</code>写起来要比<code>chumsky</code>优雅很多，因为前者的主题是一系列函数指针，类型很清晰，但是后者是泛型对象，一旦报错就是嵌套几十层的泛型可读性几乎为零，而且前者是<code>PEC</code>(Parser Expression Combinator)，可以把每个函数的职责划分得很清楚，而后者是 <code>PEG</code>(Parser Expression Generator)，相对来说没有这么优雅。但是这一切都被左递归打破了。大多数学生都知道，消除左递归的方法就是重写文法，然而重写文法会导致每个产生式之间的大量耦合，使得原来职责清晰的函数变得很答辩。而<code>chumsky</code>使用了<code>packrat</code>算法(求证中)，来实现对左递归的消除，大大提高了产生式的可读性，虽然仍然需要解决一部分的优先级问题，但是比起<code>nom</code>来说已经是好太多了</li>\\n<li>错误恢复和抛出：在编译器中，错误处理其实是很重要的一部分，这直接关系到用户的编程体验，<code>chumsky</code>恰恰是考虑到了这点，它有一个孪生的<a href=\\"https://github.com/zesterer/ariadne\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">ariadne</a>库，可以生成一些可视化程度较高的错误信息，而且在分析的过程中提供了错误恢复的操作，这些都是<code>nom</code>缺乏的</li>\\n</ol>","autoDesc":true}`);export{e as data};
